import{_ as s,o as e,c as i,a4 as n}from"./chunks/framework.Cqne-ChA.js";const u=JSON.parse('{"title":"Quick Start to zopen community","description":"","frontmatter":{},"headers":[],"relativePath":"Guides/QuickStart.md","filePath":"Guides/QuickStart.md","lastUpdated":1776677767000}'),t={name:"Guides/QuickStart.md"};function p(l,a,o,r,d,h){return e(),i("div",null,[...a[0]||(a[0]=[n(`<h1 id="quick-start-to-zopen-community" tabindex="-1">Quick Start to zopen community <a class="header-anchor" href="#quick-start-to-zopen-community" aria-label="Permalink to &quot;Quick Start to zopen community&quot;">​</a></h1><p>zopen community provides a package manager for installation of unsupported Open Source tools that run native on your z/OS system.</p><p>zopen community also provides an easy to use tool for building these same tools from source code on your z/OS system.</p><p>Whether you want to <em>use</em> the tools or also <em>improve</em> the tools is up to you.</p><p>If you have installed a version of the zopen package manager prior to September 2023, please note you will need to <a href="./Migration">migrate to the new package manager</a>.</p><h2 id="installing-zopen-package-manager" tabindex="-1">Installing zopen package manager <a class="header-anchor" href="#installing-zopen-package-manager" aria-label="Permalink to &quot;Installing zopen package manager&quot;">​</a></h2><p>Before installing, ensure <strong>auto-conversion</strong> is enabled by checking the environment variables <code>_BPXK_AUTOCVT</code> and <code>_CEE_RUNOPTS</code>. If they are not set, run:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> _BPXK_AUTOCVT</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;ON&quot;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> _CEE_RUNOPTS</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;FILETAG(AUTOCVT,AUTOTAG)&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><hr><h3 id="quick-install-if-curl-and-bash-are-available" tabindex="-1">Quick Install (if <code>curl</code> and <code>bash</code> are available) <a class="header-anchor" href="#quick-install-if-curl-and-bash-are-available" aria-label="Permalink to &quot;Quick Install (if \`curl\` and \`bash\` are available)&quot;">​</a></h3><p>Run the following one-liner:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bash</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;$(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -fsSL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://raw.githubusercontent.com/zopencommunity/meta/HEAD/tools/zopen_install.sh)&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><hr><h3 id="manual-installation" tabindex="-1">Manual Installation <a class="header-anchor" href="#manual-installation" aria-label="Permalink to &quot;Manual Installation&quot;">​</a></h3><p>If <code>curl</code> or <code>bash</code> are <strong>not</strong> available, follow these steps:</p><ol><li><p><strong>Download the latest meta package</strong><br> Download the latest <a href="https://github.com/zopencommunity/metaport/releases" target="_blank" rel="noreferrer">meta pax file</a> to your desktop, then upload it to z/OS.</p><blockquote><p><strong>Note:</strong> Use <code>sftp</code> to transfer the file from a non-z/OS machine to z/OS to avoid ASCII/EBCDIC conversion issues.</p></blockquote></li><li><p><strong>Extract the pax file on z/OS</strong></p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pax</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -rf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> meta-</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">versio</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">n</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">.pax.Z</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></li><li><p><strong>Navigate to the uncompressed directory</strong></p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> meta-</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">versio</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">n</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></li><li><p><strong>Set up the PATH for the <code>zopen</code> tool</strong></p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">.</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./.env</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></li><li><p><strong>Initialize the zOpen environment</strong></p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">zopen</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> init</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></li><li><p><strong>Configure your zOpen environment</strong></p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> $ZOPEN_ROOTFS</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/etc/zopen-config</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><blockquote><p>Replace <code>$ZOPEN_ROOTFS</code> with the path to your zOpen file system.</p></blockquote></li><li><p><strong>Install desired tools</strong></p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">zopen</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">too</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">l</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></li><li><p><strong>Cleanup</strong><br> After installation, you can safely remove the downloaded pax file and the extracted directory:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">rm</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> meta-</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">versio</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">n</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">.pax.Z</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">rm</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -rf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> meta-</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">versio</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">n</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div></li></ol><ul><li><strong>Note</strong>: We recommend that you add the line <code>. $ZOPEN_ROOTFS/etc/zopen-config</code> to your <code>.profile</code> startup script. Alternatively, you can use <code>zopen init --append-to-profile</code> when setting up your zopen file-system.</li></ul><p>See <a href="./ThePackageManager">The package manager</a> and <a href="./developing">Developing Tools</a> for more details.</p><h2 id="getting-started-video" tabindex="-1">Getting Started Video <a class="header-anchor" href="#getting-started-video" aria-label="Permalink to &quot;Getting Started Video&quot;">​</a></h2><p>If you like learning through watching, check out our getting started video:</p><video height="1080" controls><source src="https://github.com/zopencommunity/collateral/raw/main/ZOSOpenToolsIntroV2-cropped.mp4" type="video/mp4"> Your browser does not support the video tag. </video><h2 id="upgrading-zopen-community" tabindex="-1">Upgrading zopen community <a class="header-anchor" href="#upgrading-zopen-community" aria-label="Permalink to &quot;Upgrading zopen community&quot;">​</a></h2><p>zopen community can be upgraded like so:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>$ zopen upgrade</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>In this case, all packages including the package manager, <code>zopen</code> (via the meta package manager) will be updated sequentially while being prompted to perform the update. Using the option <code>-y</code> will automatically accept all prompts as shown here:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>$ zopen upgrade -y</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="upgrading-a-single-package" tabindex="-1">Upgrading a single package <a class="header-anchor" href="#upgrading-a-single-package" aria-label="Permalink to &quot;Upgrading a single package&quot;">​</a></h2><p>Individual packages can be upgraded by specifiying the package name. For example upgrading just the package manager is accomplished like so:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>$ zopen upgrade meta -y</span></span>
<span class="line"><span>$ zopen init --re-init</span></span>
<span class="line"><span># This assumes zopen is installed in your $HOME directory</span></span>
<span class="line"><span>$ . ~/zopen/etc/zopen-config</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>Note, for users of meta 0.6.x and earlier, if the upgrade fails because of a pinned message, find the <code>.pinned</code> file and remove it. Afterwards <code>zopen upgrade meta -y</code> will work.</p><p>For example:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>$ cd ~/zopen</span></span>
<span class="line"><span>$ find . -name &quot;.pinned&quot;</span></span>
<span class="line"><span>./meta-0.6.2/.pinned</span></span>
<span class="line"><span>./usr/local/zopen/meta/meta-dt/.pinned</span></span>
<span class="line"><span>$ rm ./usr/local/zopen/meta/meta-dt/.pinned</span></span>
<span class="line"><span># This is a version installed as part of the install process and</span></span>
<span class="line"><span># can be safely removed once installed.</span></span>
<span class="line"><span>$ rm -rf ./meta-0.6.2/.pinned</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div>`,32)])])}const g=s(t,[["render",p]]);export{u as __pageData,g as default};
